const sd = $getWorkflowStaticData('global');
if (!sd.processed) sd.processed = {};
const items = $input.all();
const fresh = items.filter(i => {
  if (!i || !i.json) return false;
  const id = i.json.id || i.json.email_id || i.json.messageId;
  return id && !sd.processed[id];
});
return fresh.length ? fresh : [];

const msg = $input.item.json;
const subject = (msg.subject || '').toLowerCase();
const from    = (msg.from || msg.From || '').toLowerCase();
const snippet = (msg.snippet || msg.body || '').substring(0, 300).toLowerCase();
const text    = subject + ' ' + from + ' ' + snippet;

const CATS = {
  'factura/gasto': /factura|invoice|recibo|pago\s|cobro|cargo\s|compra|order\s|pedido|enviado|entrega|mercadopago|paypal|uber\s*eats|rappi|delivery/i,
  'banco':        /banco|bank|bbva|santander|ita[uú]|galicia|hsbc|transferencia|movimiento|tarjeta|cr[eé]dito|d[eé]bito|cuenta|saldo/i,
  'trabajo':      /trabajo|office|meet\.|zoom\.|teams\.|reuni[oó]n|proyecto|cliente|presupuesto|contrato|cotizaci[oó]n/i,
  'cita':         /turno|cita\s|appointment|reserva|confirmaci[oó]n|reminder|recordatorio|doctor|m[eé]dico|dentista|odont/i,
  'suscripcion':  /newsletter|unsubscribe|baja\s|subscription|suscripci[oó]n|spotify|netflix|adobe|github|notion/i,
  'alerta':       /alerta|alert|security|seguridad|verificaci[oó]n|c[oó]digo|otp\s|acceso\s|login\s|suspicious|intento/i,
  'personal':     /querido|estimado|hola\s|saludos|familia|amigo|cumple|felicit/i,
};

let categoria = 'otro';
for (const [cat, re] of Object.entries(CATS)) {
  if (re.test(text)) { categoria = cat; break; }
}

const urgente = ['banco','alerta','cita'].includes(categoria) ||
                /urgente|urgent|importante|asap/i.test(text);

const accion = { 'factura/gasto':'gastos', 'cita':'agenda', 'suscripcion':'archivar' }[categoria] || 'ninguna';

const fecha = msg.date
  ? new Date(msg.date).toISOString().split('T')[0]
  : new Date().toISOString().split('T')[0];

const fromClean = (msg.from || msg.From || 'desconocido')
  .replace(/<[^>]+>/g, '').trim().substring(0, 60);

const asunto = (msg.subject || '(sin asunto)').substring(0, 100);
const cuerpo = (msg.snippet || msg.text || '').substring(0, 400);

return { json: {
  email_id: msg.id,
  fecha,
  de: fromClean,
  asunto,
  categoria,
  cuerpo_preview: cuerpo,
  urgente: urgente ? 'SI' : 'NO',
  accion_sugerida: accion,
  estado: 'nuevo'
}};

