const prev = $('Code: Clasificar').item.json;
const raw  = $input.item.json;

let resumen = prev.cuerpo_preview?.substring(0, 100) || '';
try {
  const choice = raw.choices?.[0]?.message?.content || '';
  if (choice.trim()) resumen = choice.trim().replace(/[*_`#]/g,'').substring(0, 120);
} catch(e) {}

return { json: {
  email_id:        prev.email_id,
  fecha:           prev.fecha,
  de:              prev.de,
  asunto:          prev.asunto,
  categoria:       prev.categoria,
  resumen,
  urgente:         prev.urgente,
  accion_sugerida: prev.accion_sugerida,
  estado:          prev.estado,
  leido:           'NO'
}};

const sd = $getWorkflowStaticData('global');
if (!sd.processed) sd.processed = {};
const items = $input.all();
const now = Date.now();
for (const i of items) {
  const id = i.json.email_id || i.json.id;
  if (id) sd.processed[id] = now;
}
const entries = Object.entries(sd.processed);
if (entries.length > 2000) {
  entries.sort((a,b) => a[1]-b[1]);
  sd.processed = Object.fromEntries(entries.slice(-2000));
}
return items;
